/* Basic flex container */
.navbar {
  display: flex;
  justify-content: space-between; /* Distribute items along main axis */
  align-items: center;            /* Align items along cross axis */
  padding: 1rem 2rem;
  gap: 1rem;                      /* Space between items */
}

/* Centering anything (the classic problem CSS finally solved) */
.centered {
  display: flex;
  justify-content: center; /* Horizontal center */
  align-items: center;     /* Vertical center */
  min-height: 100vh;
}

/* Flex wrapping for responsive layouts */
.card-grid {
  display: flex;
  flex-wrap: wrap;        /* Items wrap to the next line */
  gap: 1rem;
}

.card-grid .card {
  flex: 1 1 300px; /* Grow, shrink, minimum 300px wide */
}

/* Column layout */
.sidebar-layout {
  display: flex;
}

.sidebar-layout .sidebar {
  flex: 0 0 250px;  /* Fixed 250px width, no grow, no shrink */
}

.sidebar-layout .content {
  flex: 1;          /* Takes all remaining space */
}
